const FLASH_MORE = [
  {s:3, q:"Was ist eine Pityriasis lichenoides Mucha-Habermann?",a:"Febrile ulzeronekrotische Sonderform von PLEVA mit Fieber, ulzeronekrotischen Läsionen, Lymphadenopathie, Arthritis."},
  {s:3, q:"Beim AGEP zeigt das Differentialblutbild typischerweise was?",a:"Leukozytose mit Neutrophilie. Bei DRESS dagegen Eosinophilie + atypische Lymphozyten."},
  {s:3, q:"Was ist Eczema craquelé?",a:"Asteatotisches/Exsikkations-Ekzem: 'porzellanartige' Felder mit feinen Rissen, oft am Schienbein älterer Patienten im Winter."},
  {s:3, q:"Lichen sclerosus genital – SCC-Risiko bei Frauen?",a:"~5% lebenslanges Vulva-Plattenepithelkarzinom-Risiko. Lebenslange dermatologische Verlaufskontrollen."},
  {s:3, q:"Was unterscheidet Lichen planus actinicus vom klassischen LP?",a:"L. ruber actinicus: in sonnenexponierten Arealen, anuläre/melanoderme Plaques, klassisch Pat. aus dem Mittleren Osten."},
  {s:3, q:"Lichen ruber pemphigoides – Antigen?",a:"Kombination LR-Klinik + Auto-AK gegen BPAG2/BP180 (NC16A). Junge Pat. im Vergleich zum klassischen BP."},
  {s:3, q:"Welche Topika sind bei Psoriasis in der Schwangerschaft sicher?",a:"Calcipotriol topisch (limitiert), TCS Klasse I-II in begrenzter Fläche, Emollientien. Acitretin und MTX absolut KI."},
  {s:3, q:"PRP Typ VI – Assoziation?",a:"HIV-assoziiert. Antiretrovirale Therapie als wichtigster Schritt; topisch Retinoide, ggf. UVB."},
  {s:4, q:"Wann denkt man an ein TRAPS-Syndrom?",a:"TNF-Receptor-Associated Periodic Syndrome: rezidivierendes Fieber, migrierendes Erythem, Myalgien, periorbitales Ödem. Therapie IL-1- oder TNF-Inhibitoren."},
  {s:4, q:"Therapie Lyme-Karditis mit AV-Block II/III?",a:"Stationär i.v. Ceftriaxon 2 g/Tag für 14-21 Tage, Telemetrie-Monitoring, ggf. temporärer Pacer."},
  {s:4, q:"FMF (Familiäres Mittelmeerfieber) – Gen?",a:"MEFV-Gen kodiert Pyrin. Therapie: Colchicin lebenslang zur Verhinderung renaler Amyloidose."},
  {s:4, q:"Heerfordt-Syndrom?",a:"Sarkoidose-Manifestation: Uveitis + Parotitis + Fieber + Fazialisparese."},
  {s:4, q:"Kriterien zur Erstdiagnose APS?",a:"Lupus-Antikoagulans, Anti-Cardiolipin-IgG/IgM, Anti-β2GPI-IgG/IgM. ≥ 2 positive Tests im Abstand von ≥ 12 Wochen."},
  {s:4, q:"NRBC (necrolytic acral erythema) – Lokalisation und Trigger?",a:"Akrale Lokalisation mit Schuppung, oft mit Hepatitis-C-Infektion assoziiert."},
  {s:5, q:"Pemphigus vegetans Typ Hallopeau?",a:"Granulomatös-vegetierende Plaques in Intertrigines mit pustulösen Eruptionen. Subform des Pemphigus vulgaris."},
  {s:5, q:"Welcher Test sollte vor Azathioprin obligatorisch sein?",a:"TPMT-Aktivität – bei reduzierter Aktivität schwere Myelosuppression. ~10% Heterozygoten, ~0,3% Homozygoten."},
  {s:5, q:"Bullöse Ichthyose – Vererbung und Gene?",a:"Autosomal-dominant. KRT1 oder KRT10 (epidermolytische Hyperkeratose)."},
  {s:5, q:"Erythropoietische Protoporphyrie (EPP) – Klinik?",a:"FECH-Mutation. Sofort brennende Schmerzen + Erythem nach Sonnenlicht, ohne Bullae. Therapie: Afamelanotid."},
  {s:5, q:"PCT – Hauptursachen?",a:"Alkohol, Östrogene, Hepatitis C, HIV, Eisenüberladung, Nikotinabusus. Reduzierte UROD-Aktivität."},
  {s:5, q:"Mastozytose – wichtigste Mutation?",a:"KIT-D816V-Mutation (Tyrosinkinase). Tryptase im Serum, KMP bei systemischer Form."},
  {s:5, q:"Mastzelldegranulation – klassische Trigger?",a:"NSAR, Opioide, Röntgenkontrastmittel, Alkohol, scharfes Essen, Insektenstiche, mechanische Reibung (Darier-Zeichen +)."},
  {s:5, q:"M. Hailey-Hailey – Gen + Trigger?",a:"ATP2C1 (Calciumpumpe). Trigger: Hitze, Friktion, Schweiß. Therapie: Antiseptika, TCS, Botox, Laser."},
  {s:5, q:"M. Darier – Gen + Klinik?",a:"ATP2A2 (SERCA2). Hyperkeratotische Papeln in seborrhoischen Arealen, V-shaped nail nicks, palmare Pits. Acitretin/Isotretinoin."},
  {s:5, q:"Grover-Disease (transient acantholytic dermatosis)?",a:"Stamm-betonte juckende Papeln/Papulovesikel, oft im Sommer durch Schweiß/Bettlägerigkeit. Histologisch fokale akantholytische Dyskeratose."},
  {s:6, q:"Acne tarda – endokrinologische DDx?",a:"PCOS, Late-onset CAH (21-Hydroxylase-Mangel), androgenproduzierender Tumor."},
  {s:6, q:"Welcher Laser bei flachen erythematösen Aknenarben?",a:"Pulsed Dye Laser (PDL) oder Nd:YAG. Bei atrophen Narben: fraktioniert ablativer/nicht-ablativer Laser."},
  {s:6, q:"Spironolacton in der Akne-Therapie?",a:"Acne tarda bei Frauen, antiandrogene Wirkung. 50-100 mg/Tag. Cave Hyperkaliämie und Schwangerschaft."},
  {s:6, q:"SAPHO-Syndrom – Komponenten?",a:"Synovitis, Akne (insb. fulminans/conglobata), Pustulose (palmoplantar), Hyperostose, Osteitis. Sternoclavikularer Befall klassisch."},
  {s:6, q:"Rosacea fulminans (Pyoderma faciale)?",a:"Junge Frauen, Stress, Schwangerschaft. Explosives Auftreten von Papeln/Pusteln/Nodi auf Erythem im Gesicht."},
  {s:6, q:"Lupus miliaris disseminatus faciei – Bezug?",a:"Wird als Maximalform der granulomatösen Rosacea verstanden. Monomorphe hautfarbene Papeln zentrofazial."},
  {s:6, q:"Ofuji eosinophile pustulöse Follikulitis – Verlauf?",a:"Episoden alle 3-4 Wochen, selbstlimitierend nach 7-10 Tagen. Indomethacin 50 mg/Tag als First Line."},
  {s:6, q:"Welche Hauterkrankung kann nach Laser-Haarentfernung neu auftreten?",a:"Fox-Fordyce Disease (apokrine Gangokklusion mit juckenden axillären Papeln)."}
];

